// Giả lập Model
const productModel = {
  createNew: async (data) => ({ insertedId: 'product_id_123' }),
  findOneById: async (id) => ({ _id: id, name: 'Sample Product', sku: 'SAM-12345' })
};

const createNewProduct = async (productData) => {
  const sku = `${productData.name.substring(0, 3).toUpperCase()}-${Math.floor(10000 + Math.random() * 90000)}`;
  const newProductData = { ...productData, sku };

  // Gọi đến tầng Model để lưu vào CSDL
  const createdResult = await productModel.createNew(newProductData);

  // Lấy bản ghi product sau khi tạo
  const getNewProduct = await productModel.findOneById(createdResult.insertedId);

  // Trả kết quả về cho Controller
  return getNewProduct;
};

