codeExercises.solution:
const productModel = {
  createNew: async (data) => {
    if (!data.name) throw new Error('Product name is required');
    return { insertedId: 'product_id_123' };
  },
  findOneById: async (id) => ({ _id: id, name: 'Sample Product' })
};

const createNewProduct = async (productData) => {
  try {
    const createdResult = await productModel.createNew(productData);
    const getNewProduct = await productModel.findOneById(createdResult.insertedId);
    return getNewProduct;
  } catch (error) {
    // Ném lỗi ra ngoài để controller bắt
    throw error;
  }
};
